#include <iostream>
#include <openssl/bn.h>
using namespace std;
bool subset(string mainString, string subString)
{
    int mainLen = mainString.length();
    int subLen = subString.length();

    // Check if subString is longer than mainString
    if (subLen > mainLen)
        return false;

    for (int i = 0; i <= mainLen - subLen; ++i)
        // Check if the substring starting from index i in mainString is equal to subString
        if (mainString.substr(i, subLen) == subString)
            return true;

    // If no match is found
    return false;
}
int check_substr(string s1, string s2)
{
    int M = s1.length();
    int N = s2.length();
    for (int i = 0; i <= N - M; i++)
    {
        int j;
        for (j = 0; j < M; j++)
            if (s2[i + j] != s1[j])
                break;
        if (j == M)
            return i;
    }
    return -1;
}
int main()
{
    // string s1 = "hello world";
    // string s2 = "wor";
    // check_substr(s1,s2)
    BN_CTX *ctx = BN_CTX_new();
    BIGNUM *n[3] = {BN_new(), BN_new(), BN_new()}, *e = BN_new(), *d = BN_new(),
           *signature[3] = {BN_new(), BN_new(), BN_new()},
           *verify[3] = {BN_new(), BN_new(), BN_new()};

    BN_hex2bn(&n[0], "");
    // modulus of c0.pem
    BN_hex2bn(&n[1], "");
    // modulus of c1.pem
    BN_hex2bn(&n[2], "");
    // modulus of c2.pem

    BN_hex2bn(&signature[0], "");
    // signature of c0.pem

    BN_hex2bn(&signature[1], "");
    // signature of c1.pem

    BN_hex2bn(&signature[2], "");
    // signature of c2.pem

    BN_hex2bn(&e, "010001");
    // signature = message ^ d mod n
    // decrypt signature into verify
    BN_mod_exp(verify[0], signature[0], e, n[0], ctx);
    BN_mod_exp(verify[1], signature[1], e, n[1], ctx);
    BN_mod_exp(verify[2], signature[2], e, n[2], ctx);

    string hash[3] = {"1835ef034ca442c03e5c91a3f672e27c6a24397c86ea11b58d8bbd642dd99752", "444ebd67bb83f8807b3921e938ac9178b882bd50aadb11231f044cf5f08df7ce", "11b102e6b1f63e528984d6025f32ƒb138241fc88bbd7519574d70c9832d53e1e8"};
    for (int i = 0; i < 3; i++)
    {
        for (int j = 0; j < 3; j++)
        {
            if (check_substr(BN_bn2hex(verify[j]), hash[i]) == -1)
            {
                cout << "HASHES DONT MATCH" << endl;
            }
            else
            {
                cout << "HASHES MATCH" << endl;
            }
        }
    }

    // cout << "Decrypted Signature = " << BN_bn2hex(verify) << endl;
    // cout << "signature = " << BN_bn2hex(signature) << endl;
    return 0;
}